return [{
  json: {
    seniority: 'senior',
    targetRoles: ['Frontend Developer', 'Senior Frontend Developer', 'React Developer', 'React Native Developer', 'Full Stack Developer'],
    primarySkills: ['React', 'React.js', 'React Native', 'TypeScript', 'JavaScript', 'Next.js'],
    secondarySkills: ['Redux', 'GraphQL', 'Tailwind', 'Firebase', 'Node.js', 'MUI'],
    preferredModality: 'remote',
    location: 'Argentina',
    minScoreThreshold: 60,
    alertScoreThreshold: 75,
    myEmail: 'ramirotule@gmail.com'
  }
}];

const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (d.error) return null;

  let external_id = String(d.id || d.guid || d.link || Math.random());
  let title = d.title || d.position || 'Untitled';
  let company = d.company || d.company_name || (d.title && d.title.includes(' at ') ? d.title.split(' at ')[1] : 'Unknown');
  let description = d.description || d.content || d.summary || '';
  let apply_url = d.url || d.link || '';
  let posted_at = d.date || d.pubDate || d.publication_date || new Date().toISOString();

  return {
    json: {
      external_id,
      title,
      company,
      description,
      apply_url,
      posted_at,
      location: d.location || 'Remote',
      source: apply_url.includes('remoteok') ? 'remoteok' : (apply_url.includes('remotive') ? 'remotive' : 'wwr')
    }
  };
}).filter(i => i !== null);

// Deduplicación robusta
const newJobs = $('Code - Normalize All').getDocuments();
let existingIds = new Set();

try {
  const existingData = $('DB - Get Existing IDs').getDocuments();
  existingIds = new Set(existingData.map(d => String(d.json.external_id)));
} catch (e) {
  console.log('No hay IDs existentes o la DB está vacía');
}

return newJobs.filter(job => !existingIds.has(String(job.json.external_id)));

const profile = $('Config - My Profile').first().json;

return $input.all().map(item => {
  const job = item.json;
  let score = 0;
  let reasons = [];

  const titleLower = (job.title || '').toLowerCase();
  const descLower = (job.description || '').toLowerCase();

  if (profile.targetRoles.some(r => titleLower.includes(r.toLowerCase()))) {
    score += 35;
    reasons.push('Título coincide');
  }

  const matchedSkills = profile.primarySkills.filter(s => descLower.includes(s.toLowerCase()));
  score += Math.min((matchedSkills.length / profile.primarySkills.length) * 45, 45);
  if (matchedSkills.length > 0) reasons.push(`Skills: ${matchedSkills.join(', ')}`);

  if (descLower.includes(profile.seniority.toLowerCase())) {
    score += 20;
    reasons.push(`Nivel ${profile.seniority} detectado`);
  }

  return {
    json: {
      ...job,
      match_score: Math.min(Math.round(score), 100),
      reasons,
      is_hot_match: score >= profile.alertScoreThreshold
    }
  };
});
